data defines an algebraic data type (ADT). It should look like the following: data nat {
| Zero
| Succ(nat)
} data list(a) {
| Nil
| Cons(a, list(a))
} data config {
| Config( count: int, foo-path: &text, colorize: bool, )
} You can use the content of an ADT value by using match or case: define length<a>(xs: list(a)): int { // destruct ADT values using `match` match xs { | Nil => 0 | Cons(_, ys) => add-int(1, length(ys)) }
} define length-noetic<a>(xs: &list(a)): int { // read noetic ADT values using `case` case xs { | Nil => 0 | Cons(_, ys) => add-int(1, length-noetic(ys)) }
} define use-config(c: config) { // pattern-matching in `let` is also possible let Config of {count, some-path} = c in print(count)
}

