Let's see how top-level variables are compiled. Consider the following top-level functions: // (source-dir)/sample.nt // defining a top-level variable `increment`
define increment(x: int): int { add-int(x, 1)
} define get-increment(): (int) -> int { increment // using a top-level variable `increment`
} This increment and get-increment are compiled into LLVM functions like the below: ; (build-dir)/path/to/sample.ll define fastcc ptr @"this.sample.increment"(ptr %_1) { %_2 = ptrtoint ptr %_1 to i64 %_3 = add i64 %_2, 1 %_4 = inttoptr i64 %_3 to ptr ret ptr %_4
} define fastcc ptr @"this.sample.get-increment"() { ; `increment` in `get-increment` is lowered to the following code: ; calculate the size of 3-word tuples %_1 = getelementptr ptr, ptr null, i32 3 %_2 = ptrtoint ptr %_1 to i64 ; allocate memory %_3 = call fastcc ptr @malloc(i64 %_2) ; store contents %_4 = getelementptr [3 x ptr], ptr %_3, i32 0, i32 0 %_5 = getelementptr [3 x ptr], ptr %_3, i32 0, i32 1 %_6 = getelementptr [3 x ptr], ptr %_3, i32 0, i32 2 store ptr @"base.#.imm", ptr %_4 ; tuple[0] = `base.#.imm` store ptr null, ptr %_5 ; tuple[1] = null store ptr @"this.sample.increment", ptr %_6 ; tuple[2] = (function pointer) ; return the pointer to the tuple ret ptr %_3
} Incidentally, these 3-word tuples are optimized away as long as top-level variables (functions) are called directly with arguments.

