A term-level define is lifted to a top-level definition using lambda lifting. For example, consider the following example: define use-define(): int { let c = 10 in let f = // 🌟 term-level `define` with a free variable `c` define some-recursive-func(x: int): int { if eq-int(x, 0) { 0 } else { add-int(c, some-recursive-func(sub-int(x, 1))) } } in f(100)
} The code above is compiled into something like the below: // the free variable `c` is now a parameter
define some-recursive-func(c: int, x: int): int { if eq-int(x, 0) { 0 } else { let f = function (x: int) { some-recursive-func(c, x) } in add-int(c, f(sub-int(x, 1))) }
} define use-define(): int { let c = 10 in let f = function (x: int) { some-recursive-func(c, x) } in f(100)
}

